#include <string>
#include <algorithm>

using namespace std;

string solve(string s, long long k) {
    string result;
    for (char c : s) {
        if (c >= 'a' && c <= 'z') {
            result.push_back(c);
        } else if (c == '*') {
            if (!result.empty()) {
                result.pop_back();
            }
        } else if (c == '#') {
            result += result;
        } else if (c == '%') {
            reverse(result.begin(), result.end());
        }
        // Early termination if result size exceeds k to avoid unnecessary processing
        if (result.size() > k) {
            break;
        }
    }
    if (k < result.size()) {
        return string(1, result[k]);
    } else {
        return ".";
    }
}
